#!/usr/bin/env bash
# Reproduce the academic VG-iT rows used in the main manuscript.
#
# Provenance: the reported ordered rows were not generated by a separate legacy
# three-seed/G=32 benchmark. They are the ordered-method, seed-2021--2025 subset
# of the 30-seed grouping-invariance experiment:
#   3 datasets x 4 horizons x 5 seeds = 60 runs.
#
# This wrapper calls that same experiment entry point with filters. Dataset-specific
# settings remain in run_grouping_invariance.sh:
#   Solar-AL: G=16, depth=2; Electricity: G=16, depth=3; Traffic: G=32, depth=4.
# All rows use mean pooling, shifted grouping, FiLM, bf16, 100 epochs, and patience 5.

set -euo pipefail

export METHODS="ordered"
export SEEDS="2021,2022,2023,2024,2025"

echo "Reproducing the 60 ordered academic VG-iT main-result runs."
echo "For the complete 2,880-run diagnostic, invoke run_grouping_invariance.sh without filters."

exec bash scripts/run_grouping_invariance.sh
